mapper.select:
select bd.id, bd.subsidy_person_id, bdi.id as determination_item_id, bdi.subsidy_type, bdi.benefit_start_year, bdi.benefit_start_month, bd.bank_account, bd.account_name as bank_account_name, bdi.subsidy_standard, bdi.benefit_amount, bd.approval_status, bd.del_flag from benefit_determination_item bdi left join benefit_determination bd on bdi.determination_id = bd.id left join shebao_subsidy_person sp on bd.subsidy_person_id = sp.id where bd.del_flag = '0' and bdi.del_flag = '0' and bd.approval_status = 'approved'
and ( (#{subsidyType} = '1' and bdi.subsidy_type in ('land_loss','land_loss_resident')) or (#{subsidyType} = '2' and bdi.subsidy_type in ('expropriatee','expropriatee_subsidy')) or (#{subsidyType} = '3' and bdi.subsidy_type in ('demolition','demolition_resident')) or (#{subsidyType} = '4' and bdi.subsidy_type = 'village_official') or (#{subsidyType} = '5' and bdi.subsidy_type in ('teacher','teacher_subsidy')) or (#{subsidyType} not in ('1','2','3','4','5') and bdi.subsidy_type = #{subsidyType}) )
and bdi.benefit_start_year = #{benefitStartYear}
and bdi.benefit_start_month = #{benefitStartMonth}
and sp.street_office_id = #{streetOfficeId}
order by bd.id asc, bdi.id asc
